text:
{
  "formal_minutes": {
    "회의정보": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"]
    },
    "confirmed_decisions": [
      {
        "주제": "공개 릴리스 목표 시점",
        "결정": "스모크 테스트 통과 시 금요일 15:00 KST 공개 릴리스 진행"
      },
      {
        "주제": "packageName mismatch 대응 원칙",
        "결정": "mismatch 발생 시 먼저 패키지 설정을 점검하고, 계약(컨트랙트) 자체가 잘못된 경우에만 스크립트 검토"
      }
    ],
    "rejected_proposals": [
      {
        "제안": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "결론": "기각"
      }
    ],
    "internal_stretch_goals": [
      {
        "항목": "수요일 릴리스",
        "성격": "내부 스트레치 목표",
        "비고": "공식 공개 릴리스 확정안 아님"
      }
    ],
    "non_decisions": [
      {
        "항목": "README 설치 절차 검토",
        "상태": "목요일까지 가능하면 진행 제안만 있었고 확정 소유자 미지정"
      }
    ],
    "risks": [
      "잘못된 tarball 경로로 인해 릴리스 지연 가능",
      "README 설치 절차가 오래되었을 경우 릴리스 노트가 사용자에게 오해를 줄 가능"
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 수요일 내부 스트레치 목표를 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트 작성",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로 점검",
      "due": "미정",
      "status": "대기",
      "source_certainty": "확정(기한 미설정)"
    },
    {
      "owner": "미정",
      "task": "README 설치 절차 검토(목요일 가능 시)",
      "due": "목요일(권고, 확정 아님)",
      "status": "제안",
      "source_certainty": "부분확정(소유자 미지정)"
    }
  ],
  "followup_note": {
    "next_checks": [
      "금요일 10:00 KST 이후 Minjun의 스모크 테스트 결과 확인",
      "스모크 실패 시 Doyun의 트리아지 노트(action_items.md) 반영 여부 확인",
      "Hara의 tarball 경로 점검 결과 수집",
      "README 설치 절차 검토 담당자 지정 필요 여부 확인",
      "최종 릴리스 승인 권한자 확정",
      "릴리스 노트에 수요일 내부 스트레치 목표 언급 여부 결정"
    ],
    "do_not_invent": [
      "고객/외부 파트너 정보",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구",
      "미지정된 소유자·기한의 임의 확정"
    ]
  },
  "non_invention_rules": [
    "회의 원문에 없는 고객명, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "확정되지 않은 제안은 결정으로 기록하지 않는다.",
    "내부 스트레치 목표(수요일)와 공식 목표(금요일 15:00 KST)를 혼동하지 않는다.",
    "소유자/기한이 명시되지 않은 항목은 미정으로 유지한다.",
    "오픈 질문은 답을 임의로 채우지 않는다."
  ]
}
